import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';

export default function Search() {
  const results = Array.from({ length: 6 }).map((_, i) => ({
    id: i + 1,
    name: `Downtown Hub ${i + 1}`,
    location: 'Bengaluru, India',
    price: 799 + i * 50,
    rating: 4.5,
    amenities: ['Wi‑Fi', 'Meeting Rooms', 'Coffee']
  }));

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 max-w-7xl mx-auto px-6 py-10">
        <h2 className="text-2xl font-bold text-gray-900">Search Results</h2>
        <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-6">
          {results.map((r) => (
            <a key={r.id} href={`/spaces/${r.id}`} className="group border border-gray-100 rounded-2xl overflow-hidden shadow-card hover:-translate-y-0.5 transition">
              <div className="h-40 bg-gradient-to-br from-brand-100 to-brand-200" />
              <div className="p-4">
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 group-hover:text-brand-700">{r.name}</h3>
                    <p className="text-sm text-gray-600">{r.location}</p>
                  </div>
                  <div className="text-right">
                    <div className="text-brand-700 font-semibold">₹{r.price}/day</div>
                    <div className="text-sm text-gray-500">★ {r.rating}</div>
                  </div>
                </div>
                <div className="mt-3 flex flex-wrap gap-2">
                  {r.amenities.map(a => (
                    <span key={a} className="text-xs px-2 py-1 rounded-full bg-gray-100 text-gray-700">{a}</span>
                  ))}
                </div>
              </div>
            </a>
          ))}
        </div>
      </main>
      <Footer />
    </div>
  );
}
